/* BTRadioButton — radio selection atom (Figma 555:3529)
 *
 * Five states: default · active · disable · disable-active · error
 *
 * Uses native <input type="radio"> with opacity:0 overlay for accessibility.
 * The visual circle + dot are controlled via modifier classes on .bt-radio.
 */

/* ── Root ───────────────────────────────────────────────────────────────── */

.bt-radio {
  position: relative;
  display: inline-flex;
  align-items: flex-start;
  gap: var(--space-sm);
  padding: var(--space-xs);
  cursor: pointer;
}

/* No label/subtext → strip outer padding + center the circle (mirrors Flutter _hasPadding=false).
 * Applied automatically by Vue/React when both label and subtext are absent. */
.bt-radio--no-padding {
  padding: 0;
  align-items: center;
}

.bt-radio--no-padding .bt-radio__circle {
  margin-top: 0; /* cancel baseline offset — circle is already centered by align-items */
}

.bt-radio--disabled {
  cursor: not-allowed;
}

/* ── Native input overlay (a11y) ────────────────────────────────────────── */

.bt-radio__input {
  position: absolute;
  inset: 0;
  opacity: 0;
  margin: 0;
  width: 100%;
  height: 100%;
  cursor: inherit;
  z-index: 1;
}

/* ── Visual circle ──────────────────────────────────────────────────────── */

.bt-radio__circle {
  position: relative;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
  margin-top: 1px; /* optical alignment with label text baseline (suppressed in no-padding mode) */
  border-radius: var(--radius-rd);
  border: 1.5px solid var(--border-primary);
  background: var(--bg-primary);
  display: flex;
  align-items: center;
  justify-content: center;
  transition: border-color 0.15s, background 0.15s;
}

/* ── Dot (shown when active) ────────────────────────────────────────────── */

.bt-radio__dot {
  width: 8px;
  height: 8px;
  border-radius: var(--radius-rd);
  background: var(--color-brand-primary);
  opacity: 0;
  transition: opacity 0.15s;
}

/* ── State: active ──────────────────────────────────────────────────────── */

.bt-radio--active .bt-radio__circle {
  border-color: var(--color-brand-primary);
}

.bt-radio--active .bt-radio__dot {
  opacity: 1;
}

/* ── State: disabled (unchecked) ────────────────────────────────────────── */

.bt-radio--disabled .bt-radio__circle {
  background: var(--bg-secondary);
  border-color: var(--border-primary);
}

/* ── State: disabled active ─────────────────────────────────────────────── */

.bt-radio--disabled.bt-radio--active .bt-radio__circle {
  border-color: var(--border-disabled);
}

.bt-radio--disabled.bt-radio--active .bt-radio__dot {
  background: var(--text-disabled);
}

/* ── State: error ───────────────────────────────────────────────────────── */

.bt-radio--error .bt-radio__circle {
  border-color: var(--color-ext-error);
}

.bt-radio--error.bt-radio--active .bt-radio__dot {
  background: var(--color-ext-error);
}

/* ── Text block ─────────────────────────────────────────────────────────── */

.bt-radio__text {
  display: flex;
  flex-direction: column;
  gap: var(--space-xs);
}

.bt-radio__label {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
}

.bt-radio--disabled .bt-radio__label {
  color: var(--text-disabled);
}

.bt-radio__subtext {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-secondary);
}

.bt-radio--disabled .bt-radio__subtext {
  color: var(--text-disabled);
}

.bt-radio--error .bt-radio__subtext {
  color: var(--text-error);
}

/**
 * BTRadioButton — radio selection atom (Figma 555:3529).
 *
 * Use multiple BTRadioButton with the same modelValue + onChange to build
 * a radio group. Each item selects itself by calling onChange with its value.
 *
 * @example
 * const [selected, setSelected] = useState('a');
 *
 * <BTRadioButton modelValue={selected} value="a" onChange={setSelected} label="Option A" />
 * <BTRadioButton modelValue={selected} value="b" onChange={setSelected} label="Option B" subtext="Helper" />
 * <BTRadioButton modelValue={selected} value="c" onChange={setSelected} label="Disabled" disabled />
 * <BTRadioButton modelValue={selected} value="d" onChange={setSelected} label="Error" error subtext="Error msg" />
 */
import './BTRadioButton.css';
import type { BTRadioButtonProps } from './BTRadioButton.types';

export function BTRadioButton({
  modelValue,
  value,
  onChange,
  label,
  subtext,
  disabled = false,
  error = false,
  name,
  className,
}: BTRadioButtonProps) {
  const isActive = modelValue === value;

  // Mirrors Flutter's `_hasPadding = label != null || subtext != null`.
  // When embedded without label/subtext (e.g. inside BTDropdownList), padding is
  // automatically stripped and the circle centers itself.
  const classes = [
    'bt-radio',
    isActive && 'bt-radio--active',
    disabled && 'bt-radio--disabled',
    error && !disabled && 'bt-radio--error',
    !label && !subtext && 'bt-radio--no-padding',
    className,
  ]
    .filter(Boolean)
    .join(' ');

  function handleChange() {
    if (!disabled) onChange(value);
  }

  return (
    <label className={classes}>
      <input
        className="bt-radio__input"
        type="radio"
        name={name}
        value={String(value)}
        checked={isActive}
        disabled={disabled}
        aria-checked={isActive}
        onChange={handleChange}
      />

      <span className="bt-radio__circle" aria-hidden>
        <span className="bt-radio__dot" />
      </span>

      {(label || subtext) && (
        <span className="bt-radio__text">
          {label && <span className="bt-radio__label">{label}</span>}
          {subtext && <span className="bt-radio__subtext">{subtext}</span>}
        </span>
      )}
    </label>
  );
}

BTRadioButton.displayName = 'BTRadioButton';

export type BTRadioButtonValue = string | number | boolean;

export interface BTRadioButtonProps {
  /** The group's currently selected value. Active when modelValue === value. */
  modelValue: BTRadioButtonValue;
  /** This radio button's unique value within the group. */
  value: BTRadioButtonValue;
  /** Called with this button's value when clicked. */
  onChange: (value: BTRadioButtonValue) => void;
  /** Optional label text beside the radio circle. */
  label?: string;
  /** Optional helper text below the label. */
  subtext?: string;
  /** Disables interaction. */
  disabled?: boolean;
  /** Error border on circle; subtext turns error colour. */
  error?: boolean;
  /** Native name attribute for form grouping. */
  name?: string;
  /** Additional CSS class names. */
  className?: string;
}
